/* Source: styles/packages/text-field/src/ — Honeypot */
.hp-text-field {
  height: 56px;          /* $hp-text-field-height */
  border: 1px solid #E1E6ED; /* $dt-neutral-n3 */
  border-radius: 4px;    /* $hp-text-field-radius */
  padding: 24px 10px 10px 14px; /* $hp-text-field-content-padding */
}
.hp-text-field--dense   { height: 40px; padding: 10px; } /* $hp-text-field-height-dense */
.hp-text-field--focus   { border-color: #4B82FA; background: #EDF5FF; } /* $dt-primary-8 */
.hp-text-field--error   { border-color: #DE350B; } /* $dt-feedback-red-scale-2 */
.hp-text-field--disabled { background: #E1E6ED; color: #8FA0BA; }
